package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testWithSkipHeaderRecord_noArg() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat result = original.withSkipHeaderRecord();

        // withSkipHeaderRecord() returns a new CSVFormat with skipHeaderRecord true
        assertNotNull(result);
        assertNotSame(original, result);

        // Using reflection to access private field skipHeaderRecord
        Field skipHeaderRecordField = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        skipHeaderRecordField.setAccessible(true);

        boolean skipHeaderRecordValue = skipHeaderRecordField.getBoolean(result);
        assertTrue(skipHeaderRecordValue);

        // Original instance's skipHeaderRecord should not be affected
        boolean originalSkipHeaderRecord = skipHeaderRecordField.getBoolean(original);
        assertFalse(originalSkipHeaderRecord);
    }
}
